/bin/bash -lc "python3 - <<'PY'
import json,urllib.request
for id in ['GHSA-3f7h-mf4q-vrm4','GHSA-5jmj-h7xm-6q6v','GHSA-j288-q9x7-2f5v','GHSA-wwcp-26wc-3fxm','GHSA-2p5w-cvg5-gc5c','GHSA-3832-9276-x7gf']:
  with urllib.request.urlopen('https://api.osv.dev/v1/vulns/'+id) as r: v=json.load(r)
  fixed=[]; pkgs=[]
  for aff in v['affected']:
    pkgs.append(aff.get('package',{}).get('name'))
    for rng in aff.get('ranges',[]):
      for ev in rng.get('events',[]):
        if 'fixed' in ev: fixed.append(ev['fixed'])
  print(id, sorted(set(pkgs)), 'fixed', sorted(set(fixed)) or 'NONE', v.get('summary'))
PY"

